CREATE VIEW `ads_short_video_center_video_list_view` (`Id` COMMENT "主键Id", `StrategyCode` COMMENT "策略代号", `Name` COMMENT "榜单名称", `TitleId` COMMENT "标题Id", `FirstType` COMMENT "榜单一级样式:1：排行榜，2：上下滑,3:推剧通用 4折扣限时榜单 5 广告限免榜单", `SecondType` COMMENT "榜单二级样式:S1:排行榜 S2 :信息流上下滑 A1:三列多行 A2:一列带详情 A3:两列多行 H1:小图横滑 H2:大图横滑 H3:轮播", `Rows` COMMENT "行数", `Columns` COMMENT "列数", `HideRule` COMMENT "榜单隐藏规则：1 主推内容 2 主推及兜底", `HideRow` COMMENT "最小隐藏条数", `MainContentType` COMMENT "主推内容类型：1.剧目 2.算法", `BillId` COMMENT "剧单列表", `ArithmeticId` COMMENT "算法Id", `ClimbChartsType` COMMENT "主推爬榜类型 0不爬榜，1新书榜，2榜1，3榜2", `ShowRule` COMMENT "显示规则： 1,权重排序 2,随机排序 3,定时轮播", `ShowRow` COMMENT "滚动条数", `ShowMinute` COMMENT "显示分钟", `ExposureRule` COMMENT "曝光规则：0,无限制 1,单用户曝光N次后，当天不展示 2,单用户点击N次后，当天不展示 3,单用户点击N次后，活动期间不展示 4,单用户曝光N次后，活动期间不展示 5,所有用户累计点击N次后，活动期间不展示 6,所有用户累计点击N次后，当天不展示", `ExposureCount` COMMENT "曝光次数", `CreateTime` COMMENT "创建时间", `UpdateTime` COMMENT "修改时间", `ExcludeColumn`, `ApplyType` COMMENT "应用场景：1 首页", `FilterType` COMMENT "过滤规则：0,不限制 1,过滤已购买的短剧 2,过滤加入追剧的短剧 3,过滤已观看过的短剧 4,过滤观看记录是最后一集的所有完结剧 5,过滤加入追剧中最新的N部、浏览历史中最新的M部", `FilterNnum` COMMENT "过滤加入追剧中最新的N值", `FilterMnum` COMMENT "过滤浏览历史中最新的M值", `ListType` COMMENT "列表进入样式（0无，1使用单本样式，2使用多本样式）", `SecondArithmeticId` COMMENT "兜底算法ID2", `SecondClimbChartsType` COMMENT "兜底爬榜类型 0不爬榜，1新书榜，2榜1，3榜2", `LimitTimeStart` COMMENT "限时时间开始(限时榜单)", `LimitTimeEnd` COMMENT "限时时间结束(限时榜单)") AS SELECT `ods`.`a`.`Id`, `ods`.`a`.`StrategyCode`, `ods`.`a`.`Name`, `ods`.`a`.`TitleId`, `ods`.`a`.`FirstType`, `ods`.`a`.`SecondType`, `ods`.`a`.`Rows`, `ods`.`a`.`Columns`, `ods`.`a`.`HideRule`, `ods`.`a`.`HideRow`, `ods`.`a`.`MainContentType`, `ods`.`a`.`BillId`, `ods`.`a`.`ArithmeticId`, `ods`.`a`.`ClimbChartsType`, `ods`.`a`.`ShowRule`, `ods`.`a`.`ShowRow`, `ods`.`a`.`ShowMinute`, `ods`.`a`.`ExposureRule`, `ods`.`a`.`ExposureCount`, `ods`.`a`.`CreateTime`, `ods`.`a`.`UpdateTime`, `ods`.`a`.`ExcludeColumn`, `ods`.`a`.`ApplyType`, `ods`.`a`.`FilterType`, `ods`.`a`.`FilterNnum`, `ods`.`a`.`FilterMnum`, `ods`.`a`.`ListType`, `ods`.`a`.`SecondArithmeticId`, `ods`.`a`.`SecondClimbChartsType`, `ods`.`a`.`LimitTimeStart`, `ods`.`a`.`LimitTimeEnd`
FROM `ods`.`ods_tidb_short_video_center_video_list` AS `a`;